import asyncio
import json
import math
import signal
import time
import uuid
from dataclasses import dataclass, field
from typing import Dict, List, Tuple, Any, Optional

try:
    import websockets
    from websockets.server import WebSocketServerProtocol
except ImportError:
    raise SystemExit("Please install websockets: pip install websockets")


TICK_RATE = 20
BROADCAST_RATE = 10
HOST = "0.0.0.0"
PORT = 8765
WORLD_SIZE = 5000.0
PLAYER_SPEED = 8.0
MAX_HEALTH = 100
SPAWN_POINTS = [
    (100.0, 100.0),
    (400.0, 200.0),
    (800.0, 600.0),
    (1200.0, 300.0),
    (1600.0, 900.0),
    (2200.0, 1200.0),
    (2800.0, 1800.0),
    (3400.0, 2100.0),
    (4000.0, 2800.0),
    (4600.0, 3200.0),
]


def now_ms() -> int:
    return int(time.time() * 1000)


def clamp(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, v))


@dataclass
class Player:
    player_id: str
    name: str
    ws: WebSocketServerProtocol
    x: float
    y: float
    z: float = 0.0
    yaw: float = 0.0
    pitch: float = 0.0
    vx: float = 0.0
    vy: float = 0.0
    vz: float = 0.0
    health: int = MAX_HEALTH
    alive: bool = True
    connected: bool = True
    last_input_seq: int = 0
    last_seen_ms: int = field(default_factory=now_ms)
    input_state: Dict[str, Any] = field(default_factory=dict)
    weapon: str = "rifle"
    ammo: int = 30
    team: Optional[str] = None
    kills: int = 0
    deaths: int = 0

    def to_public_state(self) -> Dict[str, Any]:
        return {
            "id": self.player_id,
            "name": self.name,
            "pos": [round(self.x, 3), round(self.y, 3), round(self.z, 3)],
            "rot": [round(self.yaw, 3), round(self.pitch, 3)],
            "vel": [round(self.vx, 3), round(self.vy, 3), round(self.vz, 3)],
            "health": self.health,
            "alive": self.alive,
            "weapon": self.weapon,
            "ammo": self.ammo,
            "team": self.team,
            "kills": self.kills,
            "deaths": self.deaths,
            "ts": self.last_seen_ms,
        }


@dataclass
class Projectile:
    projectile_id: str
    owner_id: str
    x: float
    y: float
    z: float
    vx: float
    vy: float
    vz: float
    damage: int
    born_ms: int
    ttl_ms: int = 2000

    def to_state(self) -> Dict[str, Any]:
        return {
            "id": self.projectile_id,
            "owner": self.owner_id,
            "pos": [round(self.x, 3), round(self.y, 3), round(self.z, 3)],
            "vel": [round(self.vx, 3), round(self.vy, 3), round(self.vz, 3)],
            "damage": self.damage,
            "born": self.born_ms,
            "ttl": self.ttl_ms,
        }


class GameServer:
    def __init__(self) -> None:
        self.players: Dict[str, Player] = {}
        self.projectiles: Dict[str, Projectile] = {}
        self.events: List[Dict[str, Any]] = []
        self.tick_id: int = 0
        self.running: bool = True
        self.spawn_index: int = 0
        self.server = None

    def next_spawn(self) -> Tuple[float, float]:
        p = SPAWN_POINTS[self.spawn_index % len(SPAWN_POINTS)]
        self.spawn_index += 1
        return p

    def create_player(self, ws: WebSocketServerProtocol, name: str) -> Player:
        x, y = self.next_spawn()
        pid = str(uuid.uuid4())
        player = Player(
            player_id=pid,
            name=name[:24],
            ws=ws,
            x=x,
            y=y,
        )
        self.players[pid] = player
        self.events.append({
            "type": "player_join",
            "id": pid,
            "name": player.name,
            "ts": now_ms(),
        })
        return player

    def remove_player(self, player_id: str) -> None:
        p = self.players.get(player_id)
        if not p:
            return
        p.connected = False
        self.events.append({
            "type": "player_leave",
            "id": player_id,
            "ts": now_ms(),
        })
        del self.players[player_id]

    async def handler(self, ws: WebSocketServerProtocol) -> None:
        player: Optional[Player] = None
        try:
            raw = await asyncio.wait_for(ws.recv(), timeout=10)
            msg = json.loads(raw)
            if msg.get("type") != "join":
                await ws.send(json.dumps({"type": "error", "message": "first message must be join"}))
                return
            name = str(msg.get("name", "Player"))
            player = self.create_player(ws, name)
            await ws.send(json.dumps({
                "type": "welcome",
                "id": player.player_id,
                "tickRate": TICK_RATE,
                "broadcastRate": BROADCAST_RATE,
                "worldSize": WORLD_SIZE,
                "serverTime": now_ms(),
            }))
            async for raw in ws:
                try:
                    msg = json.loads(raw)
                except Exception:
                    continue
                await self.process_message(player, msg)
        except Exception:
            pass
        finally:
            if player:
                self.remove_player(player.player_id)

    async def process_message(self, player: Player, msg: Dict[str, Any]) -> None:
        t = msg.get("type")
        player.last_seen_ms = now_ms()

        if t == "input":
            player.last_input_seq = int(msg.get("seq", player.last_input_seq))
            player.input_state = {
                "moveX": float(msg.get("moveX", 0.0)),
                "moveY": float(msg.get("moveY", 0.0)),
                "jump": bool(msg.get("jump", False)),
                "sprint": bool(msg.get("sprint", False)),
                "yaw": float(msg.get("yaw", player.yaw)),
                "pitch": float(msg.get("pitch", player.pitch)),
            }
        elif t == "fire":
            self.spawn_projectile(player, msg)
        elif t == "damage":
            target_id = str(msg.get("targetId", ""))
            amount = int(msg.get("amount", 0))
            self.apply_damage(player.player_id, target_id, amount)
        elif t == "respawn":
            if not player.alive:
                x, y = self.next_spawn()
                player.x = x
                player.y = y
                player.z = 0.0
                player.health = MAX_HEALTH
                player.alive = True
                self.events.append({
                    "type": "respawn",
                    "id": player.player_id,
                    "pos": [player.x, player.y, player.z],
                    "ts": now_ms(),
                })
        elif t == "ping":
            await player.ws.send(json.dumps({"type": "pong", "ts": now_ms()}))

    def spawn_projectile(self, player: Player, msg: Dict[str, Any]) -> None:
        if not player.alive or player.ammo <= 0:
            return
        yaw = float(msg.get("yaw", player.yaw))
        pitch = float(msg.get("pitch", player.pitch))
        speed = float(msg.get("speed", 120.0))
        dx = math.cos(pitch) * math.cos(yaw)
        dy = math.cos(pitch) * math.sin(yaw)
        dz = math.sin(pitch)
        proj = Projectile(
            projectile_id=str(uuid.uuid4()),
            owner_id=player.player_id,
            x=player.x,
            y=player.y,
            z=player.z + 1.6,
            vx=dx * speed,
            vy=dy * speed,
            vz=dz * speed,
            damage=int(msg.get("damage", 25)),
            born_ms=now_ms(),
        )
        self.projectiles[proj.projectile_id] = proj
        player.weapon = str(msg.get("weapon", player.weapon))
        player.ammo = max(0, player.ammo - 1)
        self.events.append({
            "type": "fire",
            "owner": player.player_id,
            "projectile": proj.to_state(),
            "ts": now_ms(),
        })

    def apply_damage(self, attacker_id: str, target_id: str, amount: int) -> None:
        if amount <= 0:
            return
        target = self.players.get(target_id)
        attacker = self.players.get(attacker_id)
        if not target or not target.alive:
            return
        target.health = max(0, target.health - amount)
        self.events.append({
            "type": "damage",
            "attacker": attacker_id,
            "target": target_id,
            "amount": amount,
            "health": target.health,
            "ts": now_ms(),
        })
        if target.health <= 0:
            target.alive = False
            target.deaths += 1
            if attacker and attacker.player_id != target.player_id:
                attacker.kills += 1
            self.events.append({
                "type": "elimination",
                "attacker": attacker_id,
                "target": target_id,
                "ts": now_ms(),
            })

    async def game_loop(self) -> None:
        dt = 1.0 / TICK_RATE
        while self.running:
            start = time.perf_counter()
            self.tick(dt)
            elapsed = time.perf_counter() - start
            await asyncio.sleep(max(0.0, dt - elapsed))

    async def broadcast_loop(self) -> None:
        dt = 1.0 / BROADCAST_RATE
        while self.running:
            start = time.perf_counter()
            await self.broadcast_state()
            self.events.clear()
            elapsed = time.perf_counter() - start
            await asyncio.sleep(max(0.0, dt - elapsed))

    def tick(self, dt: float) -> None:
        self.tick_id += 1

        for p in list(self.players.values()):
            if not p.alive:
                p.vx = p.vy = p.vz = 0.0
                continue

            move_x = clamp(float(p.input_state.get("moveX", 0.0)), -1.0, 1.0)
            move_y = clamp(float(p.input_state.get("moveY", 0.0)), -1.0, 1.0)
            sprint = bool(p.input_state.get("sprint", False))
            p.yaw = float(p.input_state.get("yaw", p.yaw))
            p.pitch = clamp(float(p.input_state.get("pitch", p.pitch)), -1.57, 1.57)

            mag = math.sqrt(move_x * move_x + move_y * move_y)
            if mag > 1.0:
                move_x /= mag
                move_y /= mag

            speed = PLAYER_SPEED * (1.5 if sprint else 1.0)
            p.vx = move_x * speed
            p.vy = move_y * speed
            p.vz = 0.0

            p.x = clamp(p.x + p.vx * dt * 60.0, 0.0, WORLD_SIZE)
            p.y = clamp(p.y + p.vy * dt * 60.0, 0.0, WORLD_SIZE)
            p.last_seen_ms = now_ms()

        expired = []
        for proj in self.projectiles.values():
            proj.x += proj.vx * dt
            proj.y += proj.vy * dt
            proj.z += proj.vz * dt
            if now_ms() - proj.born_ms > proj.ttl_ms:
                expired.append(proj.projectile_id)
            elif proj.x < 0 or proj.y < 0 or proj.x > WORLD_SIZE or proj.y > WORLD_SIZE or proj.z < -100 or proj.z > 1000:
                expired.append(proj.projectile_id)

        for pid in expired:
            if pid in self.projectiles:
                del self.projectiles[pid]

    def build_full_state(self) -> Dict[str, Any]:
        return {
            "type": "state",
            "tick": self.tick_id,
            "serverTime": now_ms(),
            "world": {
                "size": WORLD_SIZE,
            },
            "players": [p.to_public_state() for p in self.players.values()],
            "projectiles": [p.to_state() for p in self.projectiles.values()],
            "events": self.events,
        }

    async def broadcast_state(self) -> None:
        if not self.players:
            return
        payload = json.dumps(self.build_full_state(), separators=(",", ":"))
        dead: List[str] = []
        for pid, player in self.players.items():
            try:
                await player.ws.send(payload)
            except Exception:
                dead.append(pid)
        for pid in dead:
            self.remove_player(pid)

    async def start(self) -> None:
        self.server = await websockets.serve(
            self.handler,
            HOST,
            PORT,
            max_size=2 * 1024 * 1024,
            ping_interval=20,
            ping_timeout=20,
        )
        loop = asyncio.get_running_loop()
        for sig in (signal.SIGINT, signal.SIGTERM):
            try:
                loop.add_signal_handler(sig, self.request_shutdown)
            except NotImplementedError:
                pass
        await asyncio.gather(self.game_loop(), self.broadcast_loop())

    def request_shutdown(self) -> None:
        self.running = False


async def main() -> None:
    server = GameServer()
    await server.start()


if __name__ == "__main__":
    asyncio.run(main())